<?php 
class CodeGenerator{var $upper='ABCDEFGHJKMNPQRSTXYZ';var $lower='abcdefghijklmnopqrstuvwxyz';var $num="0123456789";var $charset;var $users="ABCDEFIOUKLJabeijklouy";function __construct(){$this->charset=$this->upper.$this->lower.$this->num;}private function password_char($string){$lenth=strlen($string);$position=mt_rand(0,$lenth-1);return($string[$position]);}private function password($charset,$lenth){$return_string=$this->password_char($charset);for($x=1;$x<$lenth;$x++)$return_string.=$this->password_char($charset);return($return_string);}function GetCode($length){return $this->password($this->charset,$length);}function GetNumeric($length){return $this->password($this->num,$length);}function GetSmallString($length){return $this->password($this->lower,$length);}function GetCapString($length){return $this->password($this->upper,$length);}function GetString($length){$str=$this->lower.$this->upper;return $this->password($str,$length);}function GetCapNumeric($length){$str=$this->num.$this->upper;return $this->password($str,$length);}function GetSmallNumeric($length){$str=$this->num.$this->lower;return $this->password($str,$length);}} 
